module freq_div(
    input CLK_in,
    input RST,
    output reg CLK_50,
    output reg CLK_10,
    output reg CLK_1
);

reg [1:0] count_10;
reg [2:0] count_50;
reg [6:0] count_1;

always @(posedge CLK_in or posedge RST) begin
    if (RST) begin
        CLK_50 <= 1'b0;
        CLK_10 <= 1'b0;
        CLK_1 <= 1'b0;
        count_10 <= 2'b0;
        count_50 <= 3'b0;
        count_1 <= 7'b0;
    end
    else begin
        // 50MHz clock
        CLK_50 <= ~CLK_50;
        count_50 <= count_50 + 3'b1;
        if (count_50 == 3'b110) begin
            CLK_10 <= ~CLK_10;
            count_10 <= count_10 + 2'b1;
            if (count_10 == 2'b10) begin
                CLK_1 <= ~CLK_1;
                count_1 <= count_1 + 7'b1;
            end
        end
    end
end

endmodule
